#!/usr/bin/env python3
"""
Defense Bus — UDP multicast-style ingest for cross-layer defense telemetry.
Port 2372 — all twin layers publish defense events here.

Message types:
  defense.layer_status  — layer heartbeat
  defense.threat        — new threat detected
  defense.countermeasure — recommended action
"""

from __future__ import annotations

import asyncio
import json
import sys
from pathlib import Path
from typing import Callable

ROOT = Path(__file__).resolve().parent
sys.path.insert(0, str(ROOT))

from defense_core import SovereignDefenseCore

DEFENSE_PORT = 2372


class DefenseBus:
    def __init__(
        self,
        core: SovereignDefenseCore | None = None,
        on_update: Callable[[], None] | None = None,
    ):
        self.core = core or SovereignDefenseCore()
        self.on_update = on_update

    def handle_message(self, payload: dict) -> None:
        msg_type = payload.get("type", "")
        layer = payload.get("layer", "")

        if msg_type == "defense.layer_status":
            self.core.update_layer(
                layer,
                active=payload.get("active", False),
                quality=float(payload.get("quality", 0)),
                source=payload.get("source", "bus"),
                threat_contrib=float(payload.get("threat_contrib", 0)),
                details=payload.get("details"),
            )
        elif msg_type == "defense.isr":
            self.core.ingest_isr(
                payload.get("humans", 0), payload.get("animals", 0),
                payload.get("tracks", 0), float(payload.get("motion", 0)),
            )
        elif msg_type == "defense.sigint":
            self.core.ingest_sigint(float(payload.get("motion", 0)), payload.get("source", "bus"))
        elif msg_type == "defense.cyber":
            self.core.ingest_cyber(int(payload.get("cve_alerts", 0)), payload.get("latest_cve"))
        elif msg_type == "defense.nav":
            self.core.ingest_nav(payload.get("gns_active", False), int(payload.get("gnss_nodes", 0)))
        elif msg_type == "defense.spatial":
            self.core.ingest_spatial(int(payload.get("spike_count", 0)), payload.get("lattice_ok", False))
        elif msg_type == "defense.air_defense":
            self.core.ingest_air_defense(
                int(payload.get("aircraft", 0)),
                int(payload.get("missiles", 0)),
                int(payload.get("drones", 0)),
                int(payload.get("hostile", 0)),
                payload.get("mode", "peacetime"),
                float(payload.get("severity", 0)),
                payload.get("countermeasures"),
            )

        if self.on_update:
            self.on_update()

    class _UDPProtocol(asyncio.DatagramProtocol):
        def __init__(self, outer: "DefenseBus"):
            self.outer = outer

        def datagram_received(self, data: bytes, addr) -> None:
            try:
                self.outer.handle_message(json.loads(data.decode()))
            except (json.JSONDecodeError, UnicodeDecodeError) as exc:
                print(f"[!] Defense bus parse error from {addr}: {exc}")

    async def start_udp(self, port: int = DEFENSE_PORT) -> bool:
        loop = asyncio.get_running_loop()
        try:
            await loop.create_datagram_endpoint(
                lambda: self._UDPProtocol(self),
                local_addr=("0.0.0.0", port),
            )
            print(f"[DEFENSE] Bus listening on UDP :{port}")
            return True
        except OSError as e:
            print(f"[!] Defense bus port {port} unavailable ({e})")
            return False

    @staticmethod
    def publish(layer: str, msg_type: str, **kwargs) -> bytes:
        """Helper for layers to emit defense events."""
        payload = {"type": msg_type, "layer": layer, **kwargs}
        return json.dumps(payload).encode()

#!/usr/bin/env python3
"""Lightweight UDP publisher for any twin layer to emit defense telemetry."""

from __future__ import annotations

import json
import socket


DEFENSE_PORT = 2372
DEFENSE_HOST = "127.0.0.1"


def publish(msg_type: str, layer: str, **kwargs) -> None:
    payload = {"type": msg_type, "layer": layer, **kwargs}
    try:
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        sock.sendto(json.dumps(payload).encode(), (DEFENSE_HOST, DEFENSE_PORT))
        sock.close()
    except OSError:
        pass
